// CLX Business Signal Detection v2 — Parse Signal Response

const response = $input.item.json;
const lead = $('Split In Batches').first().json;

let rawText = '';
if (response && response.content && Array.isArray(response.content)) {
  rawText = response.content.map(c => c.text || '').join('');
} else if (response && typeof response.content === 'string') {
  rawText = response.content;
}
rawText = rawText.replace(/```json\s*/gi, '').replace(/```\s*/gi, '').trim();

let signal;
try {
  signal = JSON.parse(rawText);
} catch (e) {
  signal = {
    detected_signal: 'Manual review needed — parse error: ' + e.message,
    growth_stage: 'Established',
    recommended_campaign_type: 'general_outreach',
    signal_confidence: 'Low',
    outreach_timing: 'This Month'
  };
}

const now = new Date().toISOString();

return {
  json: {
    id: lead.id,
    detected_signal: signal.detected_signal || 'No signal detected',
    growth_stage: signal.growth_stage || 'Established',
    recommended_campaign_type: signal.recommended_campaign_type || 'general_outreach',
    signal_confidence: signal.signal_confidence || 'Low',
    outreach_timing: signal.outreach_timing || 'This Month',
    lead_status: 'Signal Detected',
    updated_at: now
  }
};

// CLX Business Signal Detection v2 — Prep Update Signal

const item = $input.item.json;

const body = {
  p_lead_id: item.id,
  p_fields: {
    detected_signal: item.detected_signal,
    growth_stage: item.growth_stage,
    recommended_campaign_type: item.recommended_campaign_type,
    signal_confidence: item.signal_confidence,
    outreach_timing: item.outreach_timing,
    lead_status: 'Signal Detected'
  }
};

console.log('PREP UPDATE:', JSON.stringify({ lead_id: item.id, status: body.p_fields.lead_status, signal: item.detected_signal }));

return { json: { ...item, rpc_body: JSON.stringify(body) } };
